import sailpoint.tools.GeneralException;

if (groupName == null || groupName.trim().length() == 0) {
    throw new GeneralException("Group name is required");
}

if (applicationName == null || applicationName.trim().length() == 0) {
    throw new GeneralException("Application name is required");
}

import sailpoint.object.Application;
import sailpoint.object.ManagedAttribute;
import sailpoint.object.Identity;
import sailpoint.tools.GeneralException;

Application app = context.getObjectByName(Application.class, applicationName);

if (app == null) {
    throw new GeneralException("Application not found: " + applicationName);
}

ManagedAttribute group = new ManagedAttribute();

group.setApplication(app);
group.setValue(groupName);
group.setDisplayName(groupName);

if (description != null) {
    group.setAttribute("description", description);
}

if (owner != null) {

    Identity ownerIdentity =
        context.getObjectByName(Identity.class, owner);

    if (ownerIdentity != null) {
        group.setOwner(ownerIdentity);
    }

}

context.saveObject(group);

result = "Group created successfully: " + groupName;
